#!/usr/bin/env node
/**
 * gen-token-names — codegen the closed TokenName vocabulary (tempdoc 557 §2.C / C1).
 *
 * The single authoritative list of design-token names lives in `tokens.css`
 * (every token MUST have a default there) plus the palette JSONs (which may
 * set the same names). This script projects that list into a TypeScript union
 * `TokenName`, so the `token()` accessor (C2) can only be called with a real
 * token name — a typo is a compile error, not a silent ghost-fallback.
 *
 * Usage:
 *   node scripts/ci/gen-token-names.mjs           # write the generated file
 *   node scripts/ci/gen-token-names.mjs --check    # exit 1 if it would change
 */
import { readFileSync, readdirSync, writeFileSync, existsSync } from 'node:fs';
import { join, extname } from 'node:path';

const TOKENS_CSS = 'modules/ui-web/src/styles/tokens.css';
const PALETTE_DIR = 'modules/ui-web/public/themes';
const OUT = 'modules/ui-web/src/shell-v0/themes/token-names.generated.ts';

const names = new Set();

// (1) tokens.css definitions — the authoritative vocabulary.
const DEF_RE = /(--[a-zA-Z0-9-]+)\s*:/g;
const css = readFileSync(TOKENS_CSS, 'utf8');
let m;
while ((m = DEF_RE.exec(css))) names.add(m[1]);

// (2) palette JSON token keys (bare, no `--`) — a theme may set a known token.
if (existsSync(PALETTE_DIR)) {
  for (const e of readdirSync(PALETTE_DIR)) {
    if (extname(e) !== '.json') continue;
    let parsed;
    try {
      parsed = JSON.parse(readFileSync(join(PALETTE_DIR, e), 'utf8'));
    } catch {
      continue;
    }
    const tokens = parsed && typeof parsed === 'object' ? parsed.tokens : null;
    if (tokens && typeof tokens === 'object') {
      for (const k of Object.keys(tokens)) names.add(k.startsWith('--') ? k : `--${k}`);
    }
  }
}

const sorted = [...names].sort();
const union = sorted.map((n) => `  | '${n}'`).join('\n');
const literals = sorted.map((n) => `  '${n}',`).join('\n');

const body = `/**
 * AUTO-GENERATED by scripts/ci/gen-token-names.mjs — DO NOT EDIT.
 *
 * The closed design-token vocabulary (tempdoc 557 §2.C). Regenerate with
 * \`node scripts/ci/gen-token-names.mjs\` after adding a token to tokens.css.
 * The \`token()\` accessor (themes/token.ts) is typed against this union, so a
 * misspelled token name is a compile error — not a silent ghost fallback.
 */

export type TokenName =
${union};

export const TOKEN_NAMES: readonly TokenName[] = [
${literals}
];
`;

if (process.argv.includes('--check')) {
  const current = existsSync(OUT) ? readFileSync(OUT, 'utf8') : '';
  if (current !== body) {
    console.error(
      `gen-token-names --check FAIL: ${OUT} is stale (${sorted.length} tokens). ` +
        `Run: node scripts/ci/gen-token-names.mjs`,
    );
    process.exit(1);
  }
  console.log(`gen-token-names OK — ${OUT} matches (${sorted.length} tokens).`);
} else {
  writeFileSync(OUT, body);
  console.log(`gen-token-names: wrote ${OUT} (${sorted.length} tokens).`);
}
